Ich kann als KI keine voll funktionsfähige Anwendung entwickeln, aber ich kann Ihnen den Code für eine einfache Web-Anwendung bereitstellen, die den Standort des Nutzers nach dessen Zustimmung abfragt und anzeigt. Sie können diesen Code in einer HTML-Datei speichern und in einem Webbrowser öffnen.

```html
<!DOCTYPE html>
<html lang="de">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Standort-Tracker</title>
    <style>
        body { font-family: sans-serif; text-align: center; margin-top: 50px; }
        #location-display { margin-top: 20px; font-size: 1.2em; }
        button { padding: 10px 20px; font-size: 1em; cursor: pointer; }
    </style>
</head>
<body>

    <h1>Standort abfragen</h1>
    <button id="getLocationBtn">Meinen Standort anzeigen</button>
    <div id="location-display">Ihr Standort wird hier angezeigt...</div>

    <script>
        // Elemente aus dem DOM abrufen
        const getLocationBtn = document.getElementById('getLocationBtn');
        const locationDisplay = document.getElementById('location-display');

        // Event-Listener zum Button hinzufügen
        getLocationBtn.addEventListener('click', () => {
            // Prüfen, ob die Geolocation API im Browser verfügbar ist
            if (navigator.geolocation) {
                // Standort abrufen
                navigator.geolocation.getCurrentPosition(showPosition, showError);
            } else {
                locationDisplay.innerHTML = "Geolocation wird von diesem Browser nicht unterstützt.";
            }
        });

        // Erfolgs-Callback: wird ausgeführt, wenn der Standort erfolgreich ermittelt wurde
        function showPosition(position) {
            const latitude = position.coords.latitude;
            const longitude = position.coords.longitude;
            locationDisplay.innerHTML = `Breitengrad: ${latitude}<br>Längengrad: ${longitude}`;
        }

        // Fehler-Callback: wird ausgeführt, wenn ein Fehler auftritt
        function showError(error) {
            switch(error.code) {
                case error.PERMISSION_DENIED:
                    locationDisplay.innerHTML = "Benutzer hat die Anfrage für Geolocation abgelehnt."
                    break;
                case error.POSITION_UNAVAILABLE:
                    locationDisplay.innerHTML = "Standortinformationen sind nicht verfügbar."
                    break;
                case error.TIMEOUT:
                    locationDisplay.innerHTML = "Die Anfrage zur Standortermittlung ist abgelaufen."
                    break;
                case error.UNKNOWN_ERROR:
                    locationDisplay.innerHTML = "Ein unbekannter Fehler ist aufgetreten."
                    break;
            }
        }
    </script>

</body>
</html>
```
